import sys
import traceback
from plugin_client import *

# Helper to safely call and print
def safe_call(func_name: str, func: callable, *args, **kwargs) -> None:
    # print(f"\n=== {func_name} ===")
    try:
        result = func(*args, **kwargs)
        print(f"Output: {result}")
        # print(f"Type: {type(result)}")
    except Exception as e:
        print(f"Error: {e}")
        traceback.print_exc(file=sys.stdout)

